DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
@var = random_subset(2, 'a'..'n', 'p'..'z', 'A'..'D', 'F'..'N', 'P'..'T', 'V'..'Z');
Context("Fraction")->variables->are($var[0] => 'Real', $var[1] => 'Real');
$m = Fraction(random_coprime([1..10], [2..10]));
$given = Formula("$m $var[0] + $var[1]");
$ans = Formula("$var[1] + $m $var[0]");
$evaluator = $ans->cmp(checker => sub{
  my ($correct, $student, $ans) = @_;
  Value->Error("This is the original expression") if ($student eq $given);
  Value->Error("This is algebraically equivalent to the given expression, but using commutativity of addition would give you something else") if (($student == $correct) && ($student ne $correct));
  return ($student eq $correct);
});

############################################################
# Body
############################################################

BEGIN_PGML
Demonstrate that you know the meanings of the various algebraic properties by applying the given algebraic property to the given expression to get a new expression.

Apply commutativity of addition to [`[$given]\text{.}`]

[_]{$evaluator}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
